  String get wireRoleOwnerInline;

  /// Role word for the protocol role value "member", lowercase for mid-sentence use (e.g. "… joined as member"). Capitalized role pills use the panelRole* keys instead. Translate as the natural mid-sentence word for an ordinary room member; the raw wire value itself is never displayed.
  ///
  /// In en, this message translates to:
  /// **'member'**
  String get wireRoleMemberInline;

  /// Role word for the protocol role value "agent" (an automated/bot participant), lowercase for mid-sentence use. Capitalized role pills use the panelRole* keys instead. Translate as the natural mid-sentence word for an automated agent; the raw wire value itself is never displayed.
  ///
  /// In en, this message translates to:
  /// **'agent'**
  String get wireRoleAgentInline;

  /// Member lifecycle status shown in roster pills and the agent-card footer: the member has been invited but has not joined yet. Standalone capitalized word (maps the protocol status value "invited").
  ///
  /// In en, this message translates to:
  /// **'Invited'**
  String get wireStatusInvited;

  /// Member lifecycle status shown in roster pills and the agent-card footer: the member left the room voluntarily (past tense of "to leave"). Standalone capitalized word (maps the protocol status value "left").
  ///
  /// In en, this message translates to:
  /// **'Left'**
  String get wireStatusLeft;

  /// Member lifecycle status shown in roster pills and the agent-card footer: the member was removed from the room by someone else. Standalone capitalized word (maps the protocol status value "removed").
  ///
  /// In en, this message translates to:
  /// **'Removed'**
  String get wireStatusRemoved;

  /// Peer connection path label in the room-header connection chip: traffic flows over a direct peer-to-peer connection. Lowercase, appears inside the chip's state label mid-phrase (maps the protocol path value "direct").
  ///
  /// In en, this message translates to:
  /// **'direct'**
  String get wirePathDirect;

  /// Peer connection path label in the room-header connection chip: traffic is routed through a relay server rather than directly. Lowercase, appears inside the chip's state label mid-phrase (maps the protocol path value "relay"). Networking term — keep the established local term for a relay if one exists.
  ///
  /// In en, this message translates to:
  /// **'relay'**
  String get wirePathRelay;

  /// Daemon mode word shown in the Settings daemon summary: local-only loopback mode (no real networking; used for testing). Lowercase, mid-sentence. "Loopback" is a networking term — prefer the established technical term in the target language; the protocol mode value itself is never shown.
  ///
  /// In en, this message translates to:
  /// **'loopback'**
  String get wireModeLoopback;

  /// Daemon mode word shown in the Settings daemon summary: normal networked operation (as opposed to loopback test mode). Lowercase, mid-sentence (maps the protocol mode value "real").
  ///
  /// In en, this message translates to:
  /// **'real'**
  String get wireModeReal;

  /// Client connection state, lowercase for mid-sentence use: the app is connected to its local daemon. Standalone capitalized badges use the shellConn* keys instead.
  ///
  /// In en, this message translates to:
  /// **'connected'**
  String get wireConnConnectedInline;

  /// Client connection state, lowercase for mid-sentence use: the app is establishing its first connection to the local daemon (in progress). Standalone capitalized badges use the shellConn* keys instead.
  ///
  /// In en, this message translates to:
  /// **'connecting'**
  String get wireConnConnectingInline;

  /// Client connection state, lowercase for mid-sentence use: the connection dropped and the app is trying to reconnect to the local daemon. Standalone capitalized badges use the shellConn* keys instead.
  ///
  /// In en, this message translates to:
  /// **'reconnecting'**
  String get wireConnReconnectingInline;

  /// Client connection state, lowercase for mid-sentence use: the app has no connection to the local daemon. Standalone capitalized badges use the shellConn* keys instead.
  ///
  /// In en, this message translates to:
  /// **'disconnected'**
  String get wireConnDisconnectedInline;

  /// Hint text of the advanced daemon-readable file-path field on the Files tab share card — an EXAMPLE filesystem path; localize the words (e.g. FR '/chemin/vers/rapport.pdf'), keep it an absolute path.
  ///
  /// In en, this message translates to:
  /// **'/path/to/report.pdf'**
  String get panelPathPlaceholder;
}

class _AppStringsDelegate extends LocalizationsDelegate<AppStrings> {
  const _AppStringsDelegate();

  @override
  Future<AppStrings> load(Locale locale) {
    return SynchronousFuture<AppStrings>(lookupAppStrings(locale));
  }

  @override
  bool isSupported(Locale locale) =>
      <String>['en', 'fr'].contains(locale.languageCode);

  @override
  bool shouldReload(_AppStringsDelegate old) => false;
}

AppStrings lookupAppStrings(Locale locale) {
  // Lookup logic when only language code is specified.
  switch (locale.languageCode) {
    case 'en':
      return AppStringsEn();
    case 'fr':
      return AppStringsFr();
  }

  throw FlutterError(
    'AppStrings.delegate failed to load unsupported locale "$locale". This is likely '
    'an issue with the localizations generation tool. Please file an issue '
    'on GitHub with a reproducible sample app and the gen-l10n configuration '
    'that was used.',
  );
}
